// ─── CONSISTENCY SCORE HELPERS ────────────────────────────────────────────────
function getWeekDates() {
  const dates = [];
  for (let i = 6; i >= 0; i--) {
    const d = new Date(Date.now() - i * 86400000);
    dates.push(d.toISOString().slice(0,10));
  }
  return dates;
}
