const MUSCLE_XP_PER_LEVEL = (level) => level === 0 ? 100 : level * 200;

// ─── SOUND ENGINE ─────────────────────────────────────────────────────────────
// Real MP3 sounds — base64 embedded, zero network requests
const SOUND_DATA = {
  questComplete: "data:audio/mp3;base64,",
  levelUp:       "data:audio/mp3;base64,",
  message:       "data:audio/mp3;base64,",
  popup:         "data:audio/mp3;base64,",
};

// Sound aliases — map every game event to one of the 4 real sounds
const SOUND_MAP = {
  questComplete:  'questComplete',
  habitComplete:  'questComplete',
  bossDefeated:   'questComplete',
  levelUp:        'levelUp',
  xpGain:         'message',
  purchase:       'message',
  resistance:     'message',
  tap:            'popup',
  bossHit:        'popup',
  broken:         'popup',
  reset:          'popup',
};

// Web Audio API — works in Android WebView/Capacitor (new Audio() does not)
let _actx = null;
const _buffers = {};
const _pending = {};

function _getCtx() {
  if (!_actx) _actx = new (window.AudioContext || window.webkitAudioContext)();
  return _actx;
}

function _b64ToArrayBuffer(dataUri) {
  const b64 = dataUri.split(',')[1];
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr.buffer;
}

function _loadSound(key) {
  if (_buffers[key] || _pending[key]) return;
  _pending[key] = true;
  try {
    const ctx = _getCtx();
    ctx.decodeAudioData(_b64ToArrayBuffer(SOUND_DATA[key]),
      (buf) => { _buffers[key] = buf; delete _pending[key]; },
      () => { delete _pending[key]; }
    );
  } catch(e) { delete _pending[key]; }
}

function _playBuffer(key) {
  try {
    const ctx = _getCtx();
    if (ctx.state === 'suspended') ctx.resume();
    const buf = _buffers[key];
    if (!buf) return;
    const src = ctx.createBufferSource();
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.85, ctx.currentTime);
    src.buffer = buf;
    src.connect(gain);
    gain.connect(ctx.destination);
    src.start(0);
  } catch(e) {}
}

// Preload all 4 sounds on first user interaction
let _preloaded = false;
function _preloadAll() {
  if (_preloaded) return;
  _preloaded = true;
  ['questComplete','levelUp','message','popup'].forEach(_loadSound);
}

// SL touch sound — loaded once, played on every interaction
const SL_TOUCH_B64 = '';
let _slTouchAudio = null;
function playSLTouch() {
  try {
    if (!_slTouchAudio) {
      _slTouchAudio = new Audio('data:audio/mp3;base64,' + SL_TOUCH_B64);
      _slTouchAudio.volume = 0.35;
    }
    const clone = _slTouchAudio.cloneNode();
    clone.volume = 0.35;
    clone.play().catch(()=>{});
  } catch(e) {}
}
const PENALTY_SFX_RAW = '';

let _penaltyAudio = null;
function playPenaltySFX(enabled) {
  if (!enabled) return;
  try {
    if (!_penaltyAudio) {
      _penaltyAudio = new Audio('data:audio/mp3;base64,' + PENALTY_SFX_RAW);
      _penaltyAudio.volume = 0.9;
    }
    const clone = _penaltyAudio.cloneNode();
    clone.volume = 0.9;
    clone.play().catch(()=>{});
  } catch(e) {}
}


// Global sound player — call this anywhere
function playSound(name, enabled = true) {
  if (!enabled) return;
  _preloadAll();
  const key = SOUND_MAP[name] || 'popup';
  if (_buffers[key]) {
    _playBuffer(key);
  } else {
    // Not decoded yet — load then play
    _loadSound(key);
    const check = setInterval(() => {
      if (_buffers[key]) { clearInterval(check); _playBuffer(key); }
    }, 50);
    setTimeout(() => clearInterval(check), 3000);
  }
}


// ─── HAPTIC ENGINE ───────────────────────────────────────────────────────────
// Vibration patterns for each event type.
// Uses navigator.vibrate (supported in Android WebView / Capacitor).
// Falls back silently on iOS/desktop.
const HAPTIC_PATTERNS = {
  tap:            [12],                          // light tap — every button
  questComplete:  [60, 40, 80, 40, 120],          // strong triple escalating — quest done
  habitComplete:  [30, 20, 60],                  // short + long — habit streak
  levelUp:        [60, 40, 60, 40, 120],         // triple escalating — level up
  rankUp:         [80, 50, 80, 50, 80, 50, 200], // intense burst — rank up
  bossHit:        [25],                          // sharp — boss hit
  bossDefeated:   [100, 50, 100, 50, 200],       // heavy celebration
  penalty:        [80, 30, 80, 30, 80],          // harsh warning
  death:          [200, 100, 200, 100, 400],     // dramatic
  purchase:       [20, 20, 40],                  // confirm
  broken:         [150, 50, 150],                // failure
  resistance:     [60],                          // medium single
  error:          [30, 20, 30],                  // error double
  xpGain:         [15],                          // subtle
};

let _hapticEnabled = true; // module-level, synced from state

function haptic(type = 'tap') {
  if (!_hapticEnabled) return;
  try {
    const pattern = HAPTIC_PATTERNS[type] || HAPTIC_PATTERNS.tap;
    if (navigator.vibrate) {
      navigator.vibrate(pattern);
    } else if (window.Capacitor?.Plugins?.Haptics) {
      // Capacitor Haptics plugin fallback
      const H = window.Capacitor.Plugins.Haptics;
      if (type === 'tap' || type === 'bossHit' || type === 'xpGain') {
        H.impact({ style: 'light' });
      } else if (type === 'levelUp' || type === 'bossDefeated' || type === 'rankUp') {
        H.impact({ style: 'heavy' });
      } else if (type === 'penalty' || type === 'death' || type === 'broken') {
        H.notification({ type: 'error' });
      } else if (type === 'questComplete' || type === 'habitComplete' || type === 'purchase') {
        H.notification({ type: 'success' });
      } else {
        H.impact({ style: 'medium' });
      }
    }
  } catch(e) {}
}

function getTitle(level) {
  let t = TITLES[0][1];
  for (const [minLv, title] of TITLES) { if (level >= minLv) t = title; }
  return t;
}
function xpForLevel(n) { return Math.round(1000 * Math.pow(n, 1.5)); }
function getRankForLevel(level) {
  if (level >= 200) return 'MONARCH';
  if (level >= 100) return 'S';
  if (level >= 70)  return 'A';
  if (level >= 45)  return 'B';
  if (level >= 25)  return 'C';
  if (level >= 10)  return 'D';
  return 'E';
}

function getRankRange(rank) {
  const ranges = { E:'1–9', D:'10–24', C:'25–44', B:'45–69', A:'70–99', S:'100–199', MONARCH:'200' };
  return ranges[rank] || '';
}
function getDailyQuote(rank) {
  const q = QUOTES[rank] || QUOTES.E;
  const idx = Math.floor(Date.now() / 86400000) % q.length;
  return q[idx];
}
function todayStr() { return new Date().toISOString().slice(0,10); }
function getMidnightTs() {
  const d = new Date();
  // Always set to end of TODAY (23:59:59). If it's already past 23:59, set to tomorrow.
  d.setHours(23, 59, 59, 999);
  if (d.getTime() <= Date.now()) {
    d.setDate(d.getDate() + 1);
    d.setHours(23, 59, 59, 999);
  }
  return d.getTime();
}
function getNextSundayTs() {
  const d = new Date(); d.setHours(23,59,59,999);
  const day = d.getDay(); // 0=Sun
  const daysUntilSun = day === 0 ? 0 : 7 - day; // if today is Sunday, end of today; else end of upcoming Sunday
  d.setDate(d.getDate() + daysUntilSun);
  return d.getTime();
}
function getWeekId() {
  // Returns "YYYY-WW" string for current ISO week
  const d = new Date();
  const jan1 = new Date(d.getFullYear(), 0, 1);
  const week = Math.ceil(((d - jan1) / 86400000 + jan1.getDay() + 1) / 7);
  return `${d.getFullYear()}-W${week}`;
}
