      newState = { ...newState,
        entropy: { ...(newState.entropy||{}), lastQuestDate: todayStr() },
        bloodline: { ...(newState.bloodline||{}), monthlyActivity: { ...(newState.bloodline?.monthlyActivity||{}), questCount: ((newState.bloodline?.monthlyActivity?.questCount)||0)+1 } },
      };
      return newState;
