      const d = +timerDays||0, h = +timerHrs||0, m = +timerMins||0;
      const deadline = (d+h+m > 0) ? Date.now() + (d*86400 + h*3600 + m*60)*1000 : null;
      const q = { id:'side_'+Date.now(), ...rest, deadline, completed:false, createdAt:Date.now() };
      return { ...state, quests:{...state.quests, side:[...( state.quests.side||[]), q]} };
