function getWeeklyMarketItems(weekId) {
  const seed = weekId.split('').reduce((s,c)=>s+c.charCodeAt(0),0);
  const shuffled = [...BLACK_MARKET_POOL].sort((a,b)=>{
    const ha = (seed*a.id.charCodeAt(0)*31)%100, hb = (seed*b.id.charCodeAt(0)*31)%100;
    return ha-hb;
  });
  return shuffled.slice(0,4).map(i=>({...i, id:i.id+'_'+weekId}));
}

