// ─────────────────────────────────────────────────────────────────────────────
// SHADOW CLONE SCREEN
// ─────────────────────────────────────────────────────────────────────────────
function ShadowCloneScreen({ state, dispatch, showNotif }) {
  const { shadowClone } = state;
  const snap = shadowClone?.snapshot;
  const today = todayStr();
  const takeSnapshot = () => { dispatch({ type:'TAKE_SHADOW_SNAPSHOT' }); showNotif('👤 Shadow Clone locked in — the race begins'); };
  const daysSince = snap ? Math.floor((Date.now()-new Date(snap.date).getTime())/86400000) : 0;
  const dailyXPRate = snap && daysSince > 0 ? Math.round((state.hunter.totalXP - snap.totalXP) / daysSince) : 0;
  const cloneProjectedXP = snap ? snap.totalXP + (dailyXPRate * daysSince) : 0;
  const youAhead = state.hunter.totalXP >= cloneProjectedXP;
  const gap = Math.abs(state.hunter.totalXP - cloneProjectedXP);
  return (
    <div className="scrollable" style={{ height:'100%', padding:'12px 16px 24px' }}>
      <div className="cinzel" style={{ fontSize:16, color:'#9B59B6', letterSpacing:3, marginBottom:4 }}>👤 SHADOW CLONE</div>
      <div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:16, lineHeight:1.7 }}>A snapshot of your past self. Race against who you were.</div>
      {!snap ? (
        <div style={{ textAlign:'center', padding:'32px 16px' }}>
          <div style={{ fontSize:48, marginBottom:12 }}>👤</div>
          <div className="cinzel" style={{ fontSize:13, color:'#9B59B6', marginBottom:8 }}>NO CLONE EXISTS</div>
          <div style={{ fontSize:12, color:'var(--text-dim)', marginBottom:20, lineHeight:1.7 }}>Lock in your current stats to create a Shadow Clone. Return in days and race against your past self.</div>
          <button onClick={takeSnapshot} style={{ padding:'12px 28px', borderRadius:8, cursor:'pointer', background:'rgba(155,89,182,0.15)', border:'2px solid #9B59B6', color:'#9B59B6', fontFamily:'Cinzel,serif', fontSize:12, letterSpacing:2 }}>CREATE SHADOW CLONE</button>
        </div>
      ) : (
        <>
          <div className="panel" style={{ padding:14, marginBottom:12, borderColor:`${youAhead?'rgba(46,204,113,0.3)':'rgba(231,76,60,0.3)'}` }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
              <div className="cinzel" style={{ fontSize:16, color:youAhead?'#2ECC71':'#E74C3C' }}>{youAhead?'🏃 YOU\'RE AHEAD':'⚠️ CLONE IS AHEAD'}</div>
              <div style={{ textAlign:'right' }}>
                <div className="cinzel" style={{ fontSize:22, color:youAhead?'#2ECC71':'#E74C3C' }}>{youAhead?'+':'-'}{gap.toLocaleString()}</div>
                <div style={{ fontSize:9, color:'var(--text-dim)' }}>XP gap</div>
              </div>
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, marginBottom:8 }}>
              {[{l:'YOU',v:state.hunter.totalXP.toLocaleString()+' XP',c:'var(--mana)',sub:'Lv.'+state.hunter.level},{l:'SHADOW',v:snap.totalXP.toLocaleString()+' XP',c:'#9B59B6',sub:'Lv.'+snap.level+' (snapshot)'}].map(s=>(
                <div key={s.l} style={{ padding:'10px', borderRadius:7, background:'rgba(255,255,255,0.03)', border:'1px solid rgba(255,255,255,0.07)', textAlign:'center' }}>
                  <div style={{ fontSize:9, color:'var(--text-dim)', letterSpacing:2 }}>{s.l}</div>
                  <div className="cinzel" style={{ fontSize:12, color:s.c }}>{s.v}</div>
                  <div style={{ fontSize:9, color:'var(--text-dim)' }}>{s.sub}</div>
                </div>
              ))}
            </div>
            <div style={{ fontSize:9, color:'var(--text-dim)' }}>Snapshot: {snap.date} ({daysSince}d ago)</div>
          </div>
          <div className="panel" style={{ padding:14, marginBottom:12 }}>
            <div className="cinzel" style={{ fontSize:10, color:'var(--text-dim)', letterSpacing:3, marginBottom:8 }}>STAT DELTA</div>
            {Object.entries(snap.stats||{}).map(([k,v])=>{
              const cur = state.stats[k]||1; const d = cur-v;
              return (
                <div key={k} style={{ display:'flex', alignItems:'center', gap:8, marginBottom:6 }}>
                  <span style={{ width:70, fontSize:10, color:'var(--text-dim)', fontFamily:'Cinzel,serif' }}>{k.slice(0,3).toUpperCase()}</span>
                  <div style={{ flex:1, height:5, background:'rgba(255,255,255,0.05)', borderRadius:3, overflow:'hidden', position:'relative' }}>
                    <div style={{ position:'absolute', height:'100%', width:`${Math.min(100,v*2)}%`, background:'#9B59B666', borderRadius:3 }}/>
                    <div style={{ position:'absolute', height:'100%', width:`${Math.min(100,cur*2)}%`, background:d>=0?'#2ECC71':'#E74C3C', borderRadius:3, opacity:0.8 }}/>
                  </div>
                  <span className="cinzel" style={{ fontSize:11, color:d>0?'#2ECC71':d<0?'#E74C3C':'var(--text-dim)', width:30, textAlign:'right' }}>{d>0?'+':''}{d}</span>
                </div>
              );
            })}
          </div>
          {!youAhead && <div style={{ padding:'12px 14px', borderRadius:10, background:'rgba(231,76,60,0.08)', border:'2px solid rgba(231,76,60,0.3)', marginBottom:12, fontSize:11, color:'rgba(231,76,60,0.8)' }}>⚠️ THE ECHO AWAKENS — your shadow is pulling ahead. Earn XP to overtake it before it spawns as a dungeon boss.</div>}
          <button onClick={takeSnapshot} style={{ width:'100%', padding:'10px', borderRadius:8, cursor:'pointer', background:'rgba(155,89,182,0.08)', border:'1px solid rgba(155,89,182,0.25)', color:'#9B59B6', fontFamily:'Cinzel,serif', fontSize:10, letterSpacing:2 }}>🔄 RESET SNAPSHOT</button>
        </>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// NEMESIS SCREEN
// ─────────────────────────────────────────────────────────────────────────────
function NemesisScreen({ state, dispatch, addXP, showNotif }) {
  const nemesis = state.nemesis || { traits:[], hp:500, maxHp:500, phase:'lurking', failCount:0 };
  const ap = state.hunter.attackPoints || 0;
  const hpPct = nemesis.maxHp > 0 ? Math.round((nemesis.hp/nemesis.maxHp)*100) : 100;
  const hpColor = hpPct > 60 ? '#E74C3C' : hpPct > 30 ? '#F39C12' : '#9B59B6';
  const comboAttack = (hits) => {
    if (ap < hits) return;
    dispatch({ type:'ATTACK_NEMESIS', payload: hits });
    dispatch({ type:'ATTACK_BOSS_DUNGEON', payload:{ rank:state.hunter.rank, hits } });
    if (nemesis.hp - hits <= 0) {
      addXP(5000 + (nemesis.traits?.length||0)*1000, 'nemesis');
      showNotif('💀 NEMESIS SLAIN · +' + (5000+(nemesis.traits?.length||0)*1000).toLocaleString() + ' XP');
      setTimeout(()=>dispatch({ type:'RESPAWN_NEMESIS' }), 3000);
    }
  };
  return (
    <div className="scrollable" style={{ height:'100%', padding:'12px 16px 24px' }}>
      <div className="cinzel" style={{ fontSize:16, color:'#E74C3C', letterSpacing:3, marginBottom:4 }}>💀 NEMESIS</div>
      <div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:16, lineHeight:1.7 }}>A monster born from your failures. Every penalty, skipped habit, missed quest — it remembers and grows.</div>
      {nemesis.phase === 'lurking' && (
        <div style={{ textAlign:'center', padding:'28px 16px' }}>
          <div style={{ fontSize:44, marginBottom:10 }}>👁️</div>
          <div className="cinzel" style={{ fontSize:13, color:'rgba(231,76,60,0.5)', marginBottom:8 }}>NEMESIS IS WATCHING</div>
          <div style={{ fontSize:12, color:'var(--text-dim)', marginBottom:16 }}>{nemesis.traits?.length||0} traits accumulated. Needs 3 to spawn.</div>
          <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
            {(nemesis.traits||[]).map(t=>(
              <div key={t.id} style={{ padding:'8px 12px', borderRadius:7, background:'rgba(231,76,60,0.06)', border:'1px solid rgba(231,76,60,0.15)', fontSize:11, color:'rgba(231,76,60,0.8)', textAlign:'left' }}>
                {t.label} <span style={{ color:'var(--text-dim)', fontSize:9 }}>— {t.desc}</span>
              </div>
            ))}
          </div>
        </div>
      )}
      {nemesis.phase === 'spawned' && (
        <>
          <div className="panel" style={{ padding:16, marginBottom:12, borderColor:'rgba(231,76,60,0.4)' }}>
            <div style={{ display:'flex', justifyContent:'space-between', marginBottom:8 }}>
              <div><div className="cinzel" style={{ fontSize:14, color:'var(--crimson)' }}>YOUR NEMESIS</div><div style={{ fontSize:10, color:'var(--text-dim)' }}>Born from {nemesis.traits?.length} failures</div></div>
              <div style={{ textAlign:'right' }}><div className="cinzel" style={{ fontSize:18, color:hpColor }}>{nemesis.hp}</div><div style={{ fontSize:9, color:'var(--text-dim)' }}>/{nemesis.maxHp}</div></div>
            </div>
            <div style={{ height:10, background:'rgba(255,255,255,0.05)', borderRadius:5, overflow:'hidden', marginBottom:10 }}>
              <div style={{ height:'100%', width:`${hpPct}%`, background:`linear-gradient(90deg,#E74C3C,#9B59B6)`, borderRadius:5, transition:'width 0.4s' }}/>
            </div>
            <div style={{ display:'flex', flexWrap:'wrap', gap:4 }}>
              {(nemesis.traits||[]).map(t=>(
                <span key={t.id} style={{ fontSize:9, padding:'2px 7px', borderRadius:4, background:'rgba(231,76,60,0.12)', border:'1px solid rgba(231,76,60,0.25)', color:'rgba(231,76,60,0.8)' }}>{t.label}</span>
              ))}
            </div>
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:6, marginBottom:8 }}>
            {[{h:1,e:'⚔️'},{h:20,e:'🗡️'},{h:100,e:'💥'},{h:500,e:'☄️'}].map(({h,e})=>{
              const ok = ap >= h;
              return <button key={h} onClick={()=>comboAttack(h)} disabled={!ok} style={{ padding:'10px 4px', borderRadius:8, cursor:ok?'pointer':'not-allowed', background:ok?'rgba(231,76,60,0.12)':'rgba(255,255,255,0.02)', border:`2px solid ${ok?'rgba(231,76,60,0.5)':'rgba(255,255,255,0.06)'}`, color:ok?'var(--crimson)':'rgba(255,255,255,0.15)', fontFamily:'Cinzel,serif', fontSize:10, opacity:ok?1:0.4, display:'flex', flexDirection:'column', alignItems:'center', gap:2 }}><span style={{ fontSize:14 }}>{e}</span>+{h}</button>;
            })}
          </div>
          <div style={{ fontSize:9, color:'var(--text-dim)', textAlign:'center', marginBottom:10 }}>Uses dungeon AP · {ap.toFixed(0)} available</div>
          <div style={{ padding:'10px 12px', borderRadius:8, background:'rgba(243,156,18,0.06)', border:'1px solid rgba(243,156,18,0.15)', fontSize:10, color:'#F39C12' }}>Reward on defeat: +{(5000+(nemesis.traits?.length||0)*1000).toLocaleString()} XP · all traits cleared</div>
        </>
      )}
      {nemesis.phase === 'defeated' && (
        <div style={{ textAlign:'center', padding:'28px 16px' }}>
          <div style={{ fontSize:44, marginBottom:10 }}>✨</div>
          <div className="cinzel" style={{ fontSize:14, color:'#2ECC71', marginBottom:8 }}>NEMESIS SLAIN</div>
          <div style={{ fontSize:11, color:'var(--text-dim)', lineHeight:1.7 }}>Your failures no longer haunt you — for now. Accumulate 3 more to respawn it stronger.</div>
          {nemesis.lastDefeated && <div style={{ fontSize:10, color:'var(--text-dim)', marginTop:12 }}>Defeated: {new Date(nemesis.lastDefeated).toLocaleDateString()}</div>}
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// CONSEQUENCE ENGINE
// ─────────────────────────────────────────────────────────────────────────────
function ConsequenceScreen({ state, dispatch, showNotif }) {
  const c = state.consequence || {};
  const [text, setText] = useState('');
  const [days, setDays] = useState(7);
  const [shameTimer, setShameTimer] = useState(60);
  const [shameRunning, setShameRunning] = useState(false);
  const now = Date.now();
  const isActive = c.lockedAt && !c.completed && !c.failed;
  const daysLeft = c.deadline ? Math.max(0,Math.ceil((c.deadline-now)/86400000)) : 0;
  useEffect(()=>{ if(c.deadline&&now>c.deadline&&isActive) dispatch({ type:'FAIL_CONSEQUENCE' }); },[]);
  useEffect(()=>{ if(c.failed&&!c.shameViewed&&!shameRunning){ setShameRunning(true); setShameTimer(60); } },[c.failed]);
  useEffect(()=>{
    if(!shameRunning) return;
    if(shameTimer<=0){ dispatch({ type:'VIEW_SHAME_SCREEN' }); setShameRunning(false); return; }
    const t=setTimeout(()=>setShameTimer(s=>s-1),1000); return()=>clearTimeout(t);
  },[shameRunning,shameTimer]);
  const lockIn = () => {
    if(!text.trim()) return;
    dispatch({ type:'SET_CONSEQUENCE', payload:{ text:text.trim(), deadline:Date.now()+days*86400000 } });
    setText(''); showNotif('🔒 CONSEQUENCE LOCKED IN');
  };
  if (c.failed && !c.shameViewed) return (
    <div style={{ height:'100%', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', background:'rgba(231,76,60,0.05)', padding:24 }}>
      <div style={{ fontSize:64, marginBottom:16 }}>😔</div>
      <div className="cinzel" style={{ fontSize:22, color:'var(--crimson)', letterSpacing:3, marginBottom:12, textAlign:'center' }}>YOU FAILED</div>
      <div style={{ fontSize:14, color:'rgba(255,255,255,0.7)', textAlign:'center', lineHeight:2, marginBottom:24 }}>"{c.text}"</div>
      <div style={{ fontSize:12, color:'var(--text-dim)', marginBottom:32 }}>You said you would. You didn't.</div>
      {shameRunning
        ? <div style={{ textAlign:'center' }}><div className="cinzel" style={{ fontSize:48, color:'var(--crimson)' }}>{shameTimer}</div><div style={{ fontSize:11, color:'var(--text-dim)' }}>seconds remaining</div></div>
        : <button onClick={()=>dispatch({ type:'VIEW_SHAME_SCREEN' })} style={{ padding:'12px 28px', borderRadius:8, cursor:'pointer', background:'rgba(231,76,60,0.2)', border:'2px solid var(--crimson)', color:'var(--crimson)', fontFamily:'Cinzel,serif', fontSize:12 }}>I ACCEPT MY FAILURE</button>
      }
    </div>
  );

  const REAL_WORLD_PRESETS = [
    { emoji:'🚿', label:'Cold Shower',           text:'Take a 3-minute cold shower with no warm water.' },
    { emoji:'📵', label:'No Phone 4 Hours',       text:'No phone usage for 4 hours. Not even to check.' },
    { emoji:'🍕', label:'No Junk Food Today',     text:'Zero junk food, zero snacks, zero sugar for 24 hours.' },
    { emoji:'📢', label:'Tell Someone I Failed',  text:'Tell one person in my life that I failed today. Out loud.' },
    { emoji:'😴', label:'10pm Bedtime',           text:'In bed by 10pm tonight. No exceptions.' },
    { emoji:'🏃', label:'20 Min Run',             text:'Run 20 minutes outside, no treadmill.' },
    { emoji:'📖', label:'No Entertainment',       text:'No games, shows, or YouTube until all tasks are done.' },
    { emoji:'🤐', label:'Silence Hour',           text:'One hour of complete silence. No music, no content.' },
  ];

  return (
    <div className="scrollable" style={{ height:'100%', padding:'12px 16px 24px' }}>
      <div className="cinzel" style={{ fontSize:16, color:'#E74C3C', letterSpacing:3, marginBottom:4 }}>🔒 CONSEQUENCE ENGINE</div>
      <div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:16, lineHeight:1.7 }}>Declare a real-world consequence. If you fail — you face it. No escape.</div>
      {!isActive && !c.failed && !c.completed && (
        <div className="panel" style={{ padding:14, marginBottom:12 }}>
          {/* Real-world presets */}
          <div style={{ fontSize:10, color:'var(--text-dim)', letterSpacing:2, marginBottom:8 }}>⚡ REAL-WORLD PRESETS</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:6, marginBottom:14 }}>
            {REAL_WORLD_PRESETS.map(p => (
              <button key={p.label} onClick={()=>setText(p.text)} style={{
                padding:'8px 6px', borderRadius:6, cursor:'pointer', textAlign:'left',
                background: text===p.text ? 'rgba(231,76,60,0.12)' : 'rgba(255,255,255,0.03)',
                border: `1px solid ${text===p.text ? 'var(--crimson)' : 'rgba(255,255,255,0.08)'}`,
                color: text===p.text ? 'var(--crimson)' : 'var(--text-dim)',
                fontSize:10, display:'flex', alignItems:'center', gap:6
              }}>
                <span style={{ fontSize:14 }}>{p.emoji}</span>
                <span style={{ fontFamily:'Cinzel,serif', fontSize:9, letterSpacing:0.5 }}>{p.label}</span>
              </button>
            ))}
          </div>
          <label style={{ fontSize:10, color:'var(--text-dim)', letterSpacing:2, display:'block', marginBottom:6 }}>OR WRITE YOUR OWN</label>
          <textarea className="input-dark" value={text} onChange={e=>setText(e.target.value)} placeholder="If I don't complete my Big Three this week, I delete Instagram for 7 days..." style={{ width:'100%', minHeight:70, resize:'none', fontSize:12, lineHeight:1.8, marginBottom:12 }}/>
          <div style={{ display:'flex', justifyContent:'space-between', fontSize:11, color:'var(--text-dim)', marginBottom:4 }}><span>Deadline</span><span style={{ color:'var(--crimson)', fontFamily:'Cinzel,serif' }}>{days} days</span></div>
          <input type="range" min={1} max={30} value={days} onChange={e=>setDays(+e.target.value)} style={{ width:'100%', accentColor:'var(--crimson)', marginBottom:12 }}/>
          <button onClick={lockIn} disabled={!text.trim()} style={{ width:'100%', padding:'11px', borderRadius:8, cursor:text.trim()?'pointer':'not-allowed', background:'rgba(231,76,60,0.15)', border:`2px solid ${text.trim()?'var(--crimson)':'rgba(255,255,255,0.1)'}`, color:text.trim()?'var(--crimson)':'rgba(255,255,255,0.2)', fontFamily:'Cinzel,serif', fontSize:12, letterSpacing:2, opacity:text.trim()?1:0.5 }}>🔒 LOCK IN</button>
        </div>
      )}
      {isActive && (
        <div className="panel" style={{ padding:16, marginBottom:12, borderColor:'rgba(231,76,60,0.4)' }}>
          <div style={{ fontSize:14, color:'var(--text)', lineHeight:1.8, marginBottom:12, padding:'10px 12px', background:'rgba(0,0,0,0.2)', borderRadius:7, border:'1px solid rgba(255,255,255,0.06)' }}>"{c.text}"</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, marginBottom:14 }}>
            <div style={{ padding:'10px', textAlign:'center', background:'rgba(231,76,60,0.08)', borderRadius:7, border:'1px solid rgba(231,76,60,0.2)' }}><div className="cinzel" style={{ fontSize:22, color:'var(--crimson)' }}>{daysLeft}</div><div style={{ fontSize:9, color:'var(--text-dim)' }}>DAYS LEFT</div></div>
            <div style={{ padding:'10px', textAlign:'center', background:'rgba(46,204,113,0.06)', borderRadius:7, border:'1px solid rgba(46,204,113,0.15)' }}><div className="cinzel" style={{ fontSize:22, color:'#2ECC71' }}>LIVE</div><div style={{ fontSize:9, color:'var(--text-dim)' }}>STATUS</div></div>
          </div>
          <div style={{ display:'flex', gap:8 }}>
            <button onClick={()=>{ dispatch({ type:'COMPLETE_CONSEQUENCE' }); showNotif('✅ HONOUR MAINTAINED'); }} style={{ flex:1, padding:'10px', borderRadius:7, cursor:'pointer', background:'rgba(46,204,113,0.12)', border:'1px solid rgba(46,204,113,0.3)', color:'#2ECC71', fontFamily:'Cinzel,serif', fontSize:10 }}>✅ I DID IT</button>
            <button onClick={()=>dispatch({ type:'FAIL_CONSEQUENCE' })} style={{ flex:1, padding:'10px', borderRadius:7, cursor:'pointer', background:'rgba(231,76,60,0.1)', border:'1px solid rgba(231,76,60,0.3)', color:'var(--crimson)', fontFamily:'Cinzel,serif', fontSize:10 }}>💀 I FAILED</button>
          </div>
        </div>
      )}
      {c.completed && <div style={{ textAlign:'center', padding:'24px 16px' }}><div style={{ fontSize:40 }}>🏆</div><div className="cinzel" style={{ fontSize:14, color:'#2ECC71', margin:'8px 0' }}>HONOUR MAINTAINED</div><div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:16 }}>"{c.text}"</div><button onClick={()=>dispatch({ type:'CLEAR_CONSEQUENCE' })} style={{ padding:'10px 24px', borderRadius:7, cursor:'pointer', background:'rgba(79,195,247,0.1)', border:'1px solid var(--mana)', color:'var(--mana)', fontFamily:'Cinzel,serif', fontSize:11 }}>SET NEW CONSEQUENCE</button></div>}
      {c.failed && c.shameViewed && <div style={{ textAlign:'center', padding:'24px 16px' }}><div style={{ fontSize:40 }}>📋</div><div className="cinzel" style={{ fontSize:14, color:'var(--crimson)', margin:'8px 0' }}>FAILED</div><div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:16 }}>"{c.text}"</div><div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:20 }}>Now actually do the real-world consequence. The app can't enforce it. Only your honour can.</div><button onClick={()=>dispatch({ type:'CLEAR_CONSEQUENCE' })} style={{ padding:'10px 24px', borderRadius:7, cursor:'pointer', background:'rgba(231,76,60,0.1)', border:'1px solid var(--crimson)', color:'var(--crimson)', fontFamily:'Cinzel,serif', fontSize:11 }}>ACKNOWLEDGED — START FRESH</button></div>}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// BLACK MARKET
// ─────────────────────────────────────────────────────────────────────────────
function BlackMarketScreen({ state, dispatch, addXP, showNotif }) {
  const bm = state.blackMarket || { lastSeen:null, items:[], purchases:[] };
  const weekId = getWeekId();
  useEffect(()=>{ if(!bm.lastSeen||!bm.items?.length) dispatch({ type:'REFRESH_BLACK_MARKET', payload:getWeeklyMarketItems(weekId) }); },[]);
  const items = bm.items?.length ? bm.items : getWeeklyMarketItems(weekId);
  const buy = (item) => {
    if ((bm.purchases||[]).includes(item.id)) return;
    if (item.cost>0 && (state.hunter.coins||0)<item.cost){ showNotif('❌ NOT ENOUGH COINS'); return; }
    dispatch({ type:'PURCHASE_BLACK_MARKET', payload:item.id });
    if (item.effect==='ap_boost') { dispatch({ type:'EARN_ATTACK_POINTS', payload:{ amount:item.value } }); showNotif(`⚔️ +${item.value} AP added`); }
    else if (item.effect==='nemesis_dmg') { dispatch({ type:'ATTACK_NEMESIS', payload:item.value }); showNotif(`🗡️ Nemesis took ${item.value} damage`); }
    else if (item.effect==='hp_restore') { dispatch({ type:'HEAL_HP', payload:item.value }); showNotif(`🧪 +${item.value} HP`); }
    else if (item.effect==='stat_boost') {
      const stats=['strength','intelligence','discipline','vitality','focus','charisma'];
      const s=stats[Math.floor(Math.random()*stats.length)];
      dispatch({ type:'GAIN_STAT', payload:{ stat:s, amount:item.value } });
      showNotif(`💎 +${item.value} ${s.slice(0,3).toUpperCase()} from Essence Crystal`);
    } else if (item.effect==='borrow_ap') {
      dispatch({ type:'EARN_ATTACK_POINTS', payload:{ amount:item.value } });
      dispatch({ type:'ADD_DEBT', payload:{ description:'Black Market borrowed AP', originalXP:300, currentXP:300 } });
      showNotif(`🔮 +${item.value} AP borrowed — 300 XP debt added`);
    } else { showNotif(`✅ ${item.name} applied`); }
  };
  const nextRefresh = bm.lastSeen ? new Date(bm.lastSeen+7*86400000).toLocaleDateString() : 'Next week';
  return (
    <div className="scrollable" style={{ height:'100%', padding:'12px 16px 24px' }}>
      <div className="cinzel" style={{ fontSize:16, color:'#F39C12', letterSpacing:3, marginBottom:4 }}>🏪 BLACK MARKET</div>
      <div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:6 }}>Refreshes every Monday. Items you can't find anywhere else.</div>
      <div style={{ display:'flex', justifyContent:'space-between', marginBottom:16 }}>
        <div style={{ fontSize:9, color:'var(--text-dim)' }}>Next refresh: <span style={{ color:'var(--gold)' }}>{nextRefresh}</span></div>
        <div style={{ fontSize:11, color:'var(--gold)', fontFamily:'Cinzel,serif' }}>{state.hunter.coins||0} 🪙</div>
      </div>
      <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
        {items.map(item=>{
          const bought=(bm.purchases||[]).includes(item.id);
          return (
            <div key={item.id} style={{ padding:'14px', borderRadius:10, background:bought?'rgba(255,255,255,0.02)':'rgba(243,156,18,0.06)', border:`1px solid ${bought?'rgba(255,255,255,0.06)':'rgba(243,156,18,0.25)'}`, opacity:bought?0.5:1 }}>
              <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:8 }}>
                <span style={{ fontSize:22 }}>{item.emoji}</span>
                <div style={{ flex:1 }}><div className="cinzel" style={{ fontSize:12, color:bought?'var(--text-dim)':'var(--gold)' }}>{item.name}</div><div style={{ fontSize:10, color:'var(--text-dim)', marginTop:2 }}>{item.desc}</div></div>
                <div className="cinzel" style={{ fontSize:12, color:bought?'var(--text-dim)':item.cost===0?'#2ECC71':'var(--gold)' }}>{item.cost===0?'FREE':item.cost+'🪙'}</div>
              </div>
              <button onClick={()=>buy(item)} disabled={bought} style={{ width:'100%', padding:'7px', borderRadius:6, cursor:bought?'default':'pointer', background:bought?'rgba(255,255,255,0.03)':'rgba(243,156,18,0.12)', border:`1px solid ${bought?'rgba(255,255,255,0.06)':'rgba(243,156,18,0.35)'}`, color:bought?'var(--text-dim)':'var(--gold)', fontFamily:'Cinzel,serif', fontSize:10 }}>
                {bought?'✓ ACQUIRED':item.cost===0?'TAKE IT':'PURCHASE'}
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// BLOODLINE
// ─────────────────────────────────────────────────────────────────────────────
function BloodlineScreen({ state, dispatch, showNotif }) {
  const bloodline = state.bloodline || { traits:[], monthlyActivity:{}, lastEvaluated:null };
  const currentMonth = new Date().toISOString().slice(0,7);
  const monthStart = new Date(currentMonth+'-01').getTime();
  const activity = {
    studyMinutes:(state.studySessions||[]).filter(s=>s.date>=monthStart).reduce((t,s)=>t+(s.minutes||0),0),
    workoutCount:(state.workouts||[]).filter(w=>w.date>=monthStart).length,
    questCount:(state.activityLog||[]).filter(a=>a.ts>=monthStart&&a.type==='quest_complete').length,
    penaltyCount:(state.activityLog||[]).filter(a=>a.ts>=monthStart&&a.type==='penalty').length,
    journalCount:(state.journal||[]).filter(j=>j.date>=monthStart).length,
    mockTestCount:(state.mockTests||[]).filter(t=>t.date>=monthStart).length,
    bossDefeated:(state.activityLog||[]).filter(a=>a.ts>=monthStart&&a.type==='boss_defeated').length,
    maxHabitStreak:Math.max(0,...(state.habits||[]).map(h=>h.longestStreak||0)),
  };
  const alreadyEvaluated = bloodline.lastEvaluated === currentMonth;
  const evaluateMonth = () => {
    const earned = BLOODLINE_CRITERIA.filter(c=>c.check(activity));
    let newCount=0;
    earned.forEach(c=>{ if(!(bloodline.traits||[]).find(t=>t.id===c.id)){ dispatch({ type:'EARN_BLOODLINE_TRAIT', payload:{...c, month:currentMonth} }); newCount++; } });
    dispatch({ type:'UPDATE_MONTHLY_ACTIVITY', payload:activity, meta:currentMonth });
    showNotif(newCount>0?`🩸 +${newCount} BLOODLINE TRAIT${newCount>1?'S':''} EARNED`:'📊 Evaluated — keep grinding for new traits');
  };
  return (
    <div className="scrollable" style={{ height:'100%', padding:'12px 16px 24px' }}>
      <div className="cinzel" style={{ fontSize:16, color:'#E74C3C', letterSpacing:3, marginBottom:4 }}>🩸 BLOODLINE</div>
      <div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:16, lineHeight:1.7 }}>Monthly actions permanently shape your hunter. No two hunters are the same.</div>
      <div className="panel" style={{ padding:14, marginBottom:12 }}>
        <div className="cinzel" style={{ fontSize:10, color:'var(--text-dim)', letterSpacing:3, marginBottom:10 }}>THIS MONTH — {currentMonth}</div>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:5, marginBottom:12 }}>
          {[{l:'Study hrs',v:Math.round(activity.studyMinutes/60)+'h',t:'20h'},{l:'Workouts',v:activity.workoutCount,t:'15'},{l:'Quests',v:activity.questCount,t:'60'},{l:'Penalties',v:activity.penaltyCount,t:'0'}].map(s=>(
            <div key={s.l} style={{ padding:'8px', borderRadius:6, background:'rgba(255,255,255,0.03)', border:'1px solid rgba(255,255,255,0.06)' }}>
              <div style={{ fontSize:9, color:'var(--text-dim)' }}>{s.l}</div>
              <div className="cinzel" style={{ fontSize:14, color:'var(--mana)' }}>{s.v}</div>
              <div style={{ fontSize:8, color:'var(--text-dim)' }}>target: {s.t}</div>
            </div>
          ))}
        </div>
        <div style={{ display:'flex', flexDirection:'column', gap:5, marginBottom:12 }}>
          {BLOODLINE_CRITERIA.map(c=>{
            const met=c.check(activity); const owned=(bloodline.traits||[]).find(t=>t.id===c.id);
            return (
              <div key={c.id} style={{ display:'flex', alignItems:'center', gap:8, padding:'6px 10px', borderRadius:6, background:met?'rgba(46,204,113,0.06)':'rgba(255,255,255,0.02)', border:`1px solid ${met?'rgba(46,204,113,0.2)':'rgba(255,255,255,0.05)'}` }}>
                <span style={{ fontSize:14 }}>{c.icon}</span>
                <div style={{ flex:1 }}><div style={{ fontSize:10, color:met?'#2ECC71':'var(--text-dim)', fontFamily:'Cinzel,serif' }}>{c.label}</div><div style={{ fontSize:9, color:'var(--text-dim)' }}>{c.desc}</div></div>
                <span>{owned?'✅':met?'🔓':'🔒'}</span>
              </div>
            );
          })}
        </div>
        <button onClick={evaluateMonth} disabled={alreadyEvaluated} style={{ width:'100%', padding:'10px', borderRadius:8, cursor:alreadyEvaluated?'not-allowed':'pointer', background:alreadyEvaluated?'rgba(255,255,255,0.02)':'rgba(231,76,60,0.12)', border:`1px solid ${alreadyEvaluated?'rgba(255,255,255,0.08)':'rgba(231,76,60,0.35)'}`, color:alreadyEvaluated?'var(--text-dim)':'#E74C3C', fontFamily:'Cinzel,serif', fontSize:11, opacity:alreadyEvaluated?0.5:1 }}>
          {alreadyEvaluated?'✅ EVALUATED THIS MONTH':'🩸 EVALUATE THIS MONTH'}
        </button>
      </div>
      {(bloodline.traits||[]).length>0 && (
        <div className="panel" style={{ padding:14, borderColor:'rgba(231,76,60,0.2)' }}>
          <div className="cinzel" style={{ fontSize:10, color:'var(--crimson)', letterSpacing:3, marginBottom:10 }}>YOUR BLOODLINE ({bloodline.traits.length})</div>
          {bloodline.traits.map(t=>(
            <div key={t.id} style={{ display:'flex', gap:10, padding:'10px 0', borderBottom:'1px solid rgba(255,255,255,0.04)' }}>
              <span style={{ fontSize:18 }}>{t.icon}</span>
              <div><div className="cinzel" style={{ fontSize:11, color:'#E74C3C' }}>{t.label}</div><div style={{ fontSize:9, color:'var(--text-dim)' }}>{t.desc}</div><div style={{ fontSize:10, color:'#2ECC71', marginTop:2 }}>{t.bonus}</div></div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// DEBT LEDGER
// ─────────────────────────────────────────────────────────────────────────────
function DebtLedgerScreen({ state, dispatch, addXP, showNotif }) {
  const debts = state.debtLedger || [];
  const [desc, setDesc] = useState('');
  const [xp, setXp] = useState(500);
  const active = debts.filter(d=>!d.cleared);
  const totalOwed = active.reduce((s,d)=>s+(d.currentXP||d.originalXP||0),0);
  const addDebt = () => {
    if(!desc.trim()) return;
    dispatch({ type:'ADD_DEBT', payload:{ description:desc.trim(), originalXP:xp, currentXP:xp } });
    setDesc(''); setXp(500); showNotif('📋 DEBT LOGGED — face it before it grows');
  };
  const clearDebt = (d) => {
    dispatch({ type:'CLEAR_DEBT', payload:d.id });
    addXP(d.currentXP||d.originalXP, 'debt_cleared');
    showNotif(`✅ DEBT CLEARED · +${(d.currentXP||d.originalXP).toLocaleString()} XP`);
  };
  return (
    <div className="scrollable" style={{ height:'100%', padding:'12px 16px 24px' }}>
      <div className="cinzel" style={{ fontSize:16, color:'#F39C12', letterSpacing:3, marginBottom:4 }}>📋 DEBT LEDGER</div>
      <div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:10, lineHeight:1.7 }}>Log things you told yourself you'd do but avoided. Debt grows at 10%/day. Clear it by doing the thing.</div>
      {active.length>0 && <div style={{ padding:'10px 14px', marginBottom:12, borderRadius:8, background:'rgba(243,156,18,0.08)', border:'1px solid rgba(243,156,18,0.25)', display:'flex', justifyContent:'space-between' }}><span style={{ fontSize:11, color:'var(--text-dim)' }}>Total owed</span><span className="cinzel" style={{ fontSize:14, color:'var(--gold)' }}>{totalOwed.toLocaleString()} XP</span></div>}
      <div className="panel" style={{ padding:14, marginBottom:12 }}>
        <label style={{ fontSize:10, color:'var(--text-dim)', letterSpacing:2, display:'block', marginBottom:6 }}>WHAT DID YOU AVOID?</label>
        <input className="input-dark" value={desc} onChange={e=>setDesc(e.target.value)} placeholder="Reviewed weak chapters, called my parents, went for a run..." style={{ marginBottom:10 }}/>
        <div style={{ display:'flex', justifyContent:'space-between', fontSize:11, color:'var(--text-dim)', marginBottom:4 }}><span>XP debt</span><span style={{ color:'var(--gold)', fontFamily:'Cinzel,serif' }}>{xp.toLocaleString()}</span></div>
        <input type="range" min={100} max={5000} step={100} value={xp} onChange={e=>setXp(+e.target.value)} style={{ width:'100%', accentColor:'var(--gold)', marginBottom:10 }}/>
        <button onClick={addDebt} disabled={!desc.trim()} style={{ width:'100%', padding:'10px', borderRadius:7, cursor:desc.trim()?'pointer':'not-allowed', background:'rgba(243,156,18,0.1)', border:`1px solid ${desc.trim()?'rgba(243,156,18,0.4)':'rgba(255,255,255,0.08)'}`, color:desc.trim()?'var(--gold)':'rgba(255,255,255,0.2)', fontFamily:'Cinzel,serif', fontSize:11, opacity:desc.trim()?1:0.5 }}>+ ADD DEBT</button>
      </div>
      {active.length===0&&debts.length===0&&<div style={{ textAlign:'center', padding:'24px', color:'var(--text-dim)', fontSize:12 }}>No debts. Living with complete integrity.</div>}
      {active.map(d=>{
        const days=Math.floor((Date.now()-d.createdAt)/86400000);
        const pct=Math.round(((d.currentXP||d.originalXP)-d.originalXP)/d.originalXP*100);
        return (
          <div key={d.id} className="panel" style={{ padding:14, marginBottom:10, borderColor:'rgba(243,156,18,0.25)' }}>
            <div style={{ display:'flex', justifyContent:'space-between', marginBottom:6 }}>
              <div style={{ flex:1, fontSize:12, color:'var(--text)' }}>{d.description}</div>
              <div style={{ textAlign:'right', paddingLeft:8 }}><div className="cinzel" style={{ fontSize:13, color:'var(--gold)' }}>{(d.currentXP||d.originalXP).toLocaleString()}</div><div style={{ fontSize:8, color:'var(--text-dim)' }}>XP owed</div></div>
            </div>
            <div style={{ display:'flex', justifyContent:'space-between', fontSize:9, color:'var(--text-dim)', marginBottom:8 }}>
              <span>{days}d overdue</span><span style={{ color:pct>0?'#E74C3C':'var(--text-dim)' }}>{pct>0?`+${pct}% interest`:'+0%'}</span>
            </div>
            <button onClick={()=>clearDebt(d)} style={{ width:'100%', padding:'8px', borderRadius:6, cursor:'pointer', background:'rgba(46,204,113,0.1)', border:'1px solid rgba(46,204,113,0.3)', color:'#2ECC71', fontFamily:'Cinzel,serif', fontSize:10 }}>✅ I DID IT — CLEAR (+{(d.currentXP||d.originalXP).toLocaleString()} XP)</button>
          </div>
        );
      })}
      {debts.filter(d=>d.cleared).length>0&&<div style={{ marginTop:12 }}><div className="cinzel" style={{ fontSize:9, color:'var(--text-dim)', letterSpacing:3, marginBottom:8 }}>CLEARED</div>{debts.filter(d=>d.cleared).slice(-5).reverse().map(d=><div key={d.id} style={{ padding:'7px 12px', marginBottom:5, borderRadius:7, background:'rgba(46,204,113,0.04)', border:'1px solid rgba(46,204,113,0.1)', display:'flex', justifyContent:'space-between' }}><span style={{ fontSize:11, color:'var(--text-dim)', textDecoration:'line-through' }}>{d.description}</span><span style={{ fontSize:10, color:'#2ECC71' }}>✅</span></div>)}</div>}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// ENTROPY SCREEN
// ─────────────────────────────────────────────────────────────────────────────
function EntropyScreen({ state, dispatch, showNotif }) {
  const entropy = state.entropy || {};
  const TRACKED = [
    { key:'lastWorkoutDate', stat:'strength',     label:'Strength',     emoji:'💪', decayDays:5, warnDays:4 },
    { key:'lastStudyDate',   stat:'intelligence', label:'Intelligence', emoji:'📚', decayDays:3, warnDays:2 },
    { key:'lastHabitDate',   stat:'discipline',   label:'Discipline',   emoji:'🔥', decayDays:3, warnDays:2 },
    { key:'lastQuestDate',   stat:'focus',        label:'Focus',        emoji:'⚔️', decayDays:4, warnDays:3 },
  ];
  return (
    <div className="scrollable" style={{ height:'100%', padding:'12px 16px 24px' }}>
      <div className="cinzel" style={{ fontSize:16, color:'#4FC3F7', letterSpacing:3, marginBottom:4 }}>⚡ ENTROPY</div>
      <div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:16, lineHeight:1.7 }}>Skills rust. Stats decay when neglected. The longer you wait, the more you lose.</div>
      {TRACKED.map(t=>{
        const lastDate=entropy[t.key];
        const days=lastDate?Math.floor((Date.now()-new Date(lastDate).getTime())/86400000):null;
        const isWarning=days!==null&&days>=t.warnDays;
        const isDecaying=days!==null&&days>=t.decayDays;
        const statVal=state.stats[t.stat]||1;
        const color=isDecaying?'#E74C3C':isWarning?'#F39C12':'#2ECC71';
        return (
          <div key={t.key} className="panel" style={{ padding:14, marginBottom:10, borderColor:`${color}33` }}>
            <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:8 }}>
              <span style={{ fontSize:22 }}>{t.emoji}</span>
              <div style={{ flex:1 }}><div className="cinzel" style={{ fontSize:12, color }}>{t.label}</div><div style={{ fontSize:10, color:'var(--text-dim)' }}>{lastDate?`Last: ${lastDate} (${days}d ago)`:'Never tracked'}</div></div>
              <div style={{ textAlign:'right' }}><div className="cinzel" style={{ fontSize:15, color }}>{statVal}</div><div style={{ fontSize:8, color:'var(--text-dim)' }}>current</div></div>
            </div>
            <div style={{ height:5, background:'rgba(255,255,255,0.05)', borderRadius:3, overflow:'hidden', marginBottom:6 }}>
              <div style={{ height:'100%', width:`${Math.max(0,100-((days||0)/t.decayDays)*100)}%`, background:color, borderRadius:3, transition:'width 0.5s' }}/>
            </div>
            {isDecaying&&<div style={{ fontSize:10, color:'#E74C3C', padding:'5px 8px', borderRadius:5, background:'rgba(231,76,60,0.08)', border:'1px solid rgba(231,76,60,0.2)' }}>⚠️ DECAYING — do a relevant activity to stop it</div>}
            {isWarning&&!isDecaying&&<div style={{ fontSize:10, color:'#F39C12' }}>⏳ Warning — decay in {t.decayDays-days} day{t.decayDays-days===1?'':'s'}</div>}
            {!isWarning&&days!==null&&<div style={{ fontSize:10, color:'#2ECC71' }}>✅ Active — safe for {t.decayDays-days}d</div>}
          </div>
        );
      })}
      <div style={{ padding:'10px 14px', borderRadius:8, background:'rgba(79,195,247,0.05)', border:'1px solid rgba(79,195,247,0.15)', fontSize:10, color:'var(--text-dim)', lineHeight:1.7 }}>
        Workouts reset Strength · Study sessions reset Intelligence · Habits reset Discipline · Quests reset Focus
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// FORBIDDEN ZONE
// ─────────────────────────────────────────────────────────────────────────────
function ForbiddenZoneScreen({ state, dispatch, addXP, showNotif }) {
  const fz = state.forbiddenZone || { lastUnlocked:null, bossHistory:[], currentBoss:null };
  const today = todayStr();
  const hour = new Date().getHours();
  const isMidnightWindow = hour >= 0 && hour < 4;
  const alreadyToday = fz.lastUnlocked === today;
  const boss = fz.currentBoss;
  const ap = state.hunter.attackPoints || 0;
  const hpPct = boss ? Math.max(0,(boss.hp/boss.maxHp)*100) : 0;
  const unlock = () => {
    dispatch({ type:'UNLOCK_FORBIDDEN_ZONE', payload:getDailyForbiddenBoss(today) });
    showNotif('🚪 THE FORBIDDEN ZONE OPENS');
  };
  const attack = (hits) => {
    if(!boss||ap<hits) return;
    dispatch({ type:'ATTACK_FORBIDDEN_BOSS', payload:hits });
    dispatch({ type:'ATTACK_BOSS_DUNGEON', payload:{ rank:state.hunter.rank, hits } });
    if(boss.hp-hits<=0){
      dispatch({ type:'DEFEAT_FORBIDDEN_BOSS' });
      addXP(8000,'forbidden');
      dispatch({ type:'GAIN_STAT', payload:{ stat:'discipline', amount:3 } });
      showNotif(`💀 SLAIN · +8,000 XP · +3 DISC · ${boss.reward}`);
    }
  };
  return (
    <div className="scrollable" style={{ height:'100%', padding:'12px 16px 24px' }}>
      <div className="cinzel" style={{ fontSize:16, color:'#9B59B6', letterSpacing:3, marginBottom:4 }}>🚪 FORBIDDEN ZONE</div>
      <div style={{ fontSize:11, color:'var(--text-dim)', marginBottom:16, lineHeight:1.7 }}>Opens only between 12 AM – 4 AM. Each night spawns a unique boss. Miss it and it's gone forever.</div>
      {!isMidnightWindow&&!boss&&(
        <div style={{ textAlign:'center', padding:'32px 16px', background:'rgba(155,89,182,0.04)', borderRadius:12, border:'1px solid rgba(155,89,182,0.15)' }}>
          <div style={{ fontSize:44, marginBottom:10 }}>🌙</div>
          <div className="cinzel" style={{ fontSize:13, color:'rgba(155,89,182,0.6)', marginBottom:8 }}>THE DOOR IS SEALED</div>
          <div style={{ fontSize:12, color:'var(--text-dim)' }}>Complete all daily quests, then return between 12:00 AM – 4:00 AM</div>
        </div>
      )}
      {isMidnightWindow&&!boss&&!alreadyToday&&(
        <div style={{ textAlign:'center', padding:'24px 16px' }}>
          <div style={{ fontSize:44, marginBottom:10 }}>🚪</div>
          <div className="cinzel" style={{ fontSize:13, color:'#9B59B6', marginBottom:16 }}>THE DOOR IS OPEN</div>
          <button onClick={unlock} style={{ padding:'13px 32px', borderRadius:10, cursor:'pointer', background:'rgba(155,89,182,0.15)', border:'2px solid #9B59B6', color:'#9B59B6', fontFamily:'Cinzel,serif', fontSize:12, letterSpacing:2, boxShadow:'0 0 20px rgba(155,89,182,0.3)' }}>⚔️ ENTER</button>
        </div>
      )}
      {boss&&(
        <>
          <div className="panel" style={{ padding:16, marginBottom:12, borderColor:'rgba(155,89,182,0.4)', textAlign:'center' }}>
            <div style={{ fontSize:52, marginBottom:8 }}>{boss.emoji}</div>
            <div className="cinzel" style={{ fontSize:15, color:'#9B59B6', marginBottom:4 }}>{boss.name}</div>
            <div style={{ fontSize:10, color:'var(--text-dim)', marginBottom:10, fontStyle:'italic' }}>"{boss.trait}"</div>
            <div style={{ display:'flex', justifyContent:'space-between', fontSize:11, color:'var(--text-dim)', marginBottom:4 }}><span>HP</span><span className="cinzel" style={{ color:'#9B59B6' }}>{boss.hp}/{boss.maxHp}</span></div>
            <div style={{ height:10, background:'rgba(255,255,255,0.06)', borderRadius:5, overflow:'hidden', marginBottom:8 }}>
              <div style={{ height:'100%', width:`${hpPct}%`, background:'linear-gradient(90deg,#9B59B6,#E74C3C)', borderRadius:5, transition:'width 0.4s' }}/>
            </div>
            <div style={{ fontSize:10, color:'rgba(155,89,182,0.7)' }}>Reward: {boss.reward}</div>
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:6, marginBottom:6 }}>
            {[{h:1,e:'⚔️'},{h:20,e:'🗡️'},{h:100,e:'💥'},{h:500,e:'☄️'}].map(({h,e})=>{
              const ok=ap>=h;
              return <button key={h} onClick={()=>attack(h)} disabled={!ok} style={{ padding:'10px 4px', borderRadius:8, cursor:ok?'pointer':'not-allowed', background:ok?'rgba(155,89,182,0.15)':'rgba(255,255,255,0.02)', border:`2px solid ${ok?'rgba(155,89,182,0.5)':'rgba(255,255,255,0.06)'}`, color:ok?'#9B59B6':'rgba(255,255,255,0.15)', fontFamily:'Cinzel,serif', fontSize:10, opacity:ok?1:0.4, display:'flex', flexDirection:'column', alignItems:'center', gap:2 }}><span style={{ fontSize:14 }}>{e}</span>+{h}</button>;
            })}
          </div>
          <div style={{ fontSize:9, color:'var(--text-dim)', textAlign:'center', marginBottom:10 }}>Uses dungeon AP · {ap.toFixed(0)} available</div>
        </>
      )}
      {(fz.bossHistory||[]).length>0&&(
        <div className="panel" style={{ padding:14, marginTop:12 }}>
          <div className="cinzel" style={{ fontSize:10, color:'var(--text-dim)', letterSpacing:3, marginBottom:8 }}>ENCOUNTER HISTORY</div>
          {[...fz.bossHistory].reverse().slice(0,7).map((h,i)=>(
            <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid rgba(255,255,255,0.04)' }}>
              <div><div style={{ fontSize:11, color:'var(--text)' }}>{h.bossName}</div><div style={{ fontSize:9, color:'var(--text-dim)' }}>{h.date}</div></div>
              <span style={{ fontSize:11, color:h.defeated?'#2ECC71':'var(--crimson)' }}>{h.defeated?'⚔️ SLAIN':'💀 ESCAPED'}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

