function SystemsHubScreen({ state, dispatch, addXP, showNotif }) {
  const [activeSystem, setActiveSystem] = useState('overview');
  const debts = (state.debtLedger||[]).filter(d=>!d.cleared).length;
  const nemesis = state.nemesis || {};
  const clone = state.shadowClone || {};
  const SYSTEMS = [
    { id:'shadow',      label:'Shadow Clone', emoji:'👤', color:'#9B59B6', badge:clone.echoTriggered?'!':null },
    { id:'nemesis',     label:'Nemesis',       emoji:'💀', color:'#E74C3C', badge:nemesis.phase==='spawned'?'⚠':null },
    { id:'consequence', label:'Consequence',   emoji:'🔒', color:'#E74C3C', badge:null },
    { id:'blackmarket', label:'Black Market',  emoji:'🏪', color:'#F39C12', badge:null },
    { id:'bloodline',   label:'Bloodline',     emoji:'🩸', color:'#E74C3C', badge:null },
    { id:'debt',        label:'Debt Ledger',   emoji:'📋', color:'#F39C12', badge:debts>0?debts:null },
    { id:'entropy',     label:'Entropy',       emoji:'⚡', color:'#4FC3F7', badge:null },
    { id:'forbidden',   label:'Forbidden Zone',emoji:'🚪', color:'#9B59B6', badge:null },
  ];
  if (activeSystem !== 'overview') return (
    <div style={{ height:'100%', display:'flex', flexDirection:'column' }}>
      <div style={{ padding:'10px 16px', display:'flex', alignItems:'center', gap:10, flexShrink:0, borderBottom:'1px solid var(--border)' }}>
        <button onClick={()=>setActiveSystem('overview')} style={{ background:'none', border:'none', cursor:'pointer', color:'var(--mana)', fontSize:16, padding:4 }}>←</button>
        <div className="cinzel" style={{ fontSize:13, color:'var(--mana)', letterSpacing:2 }}>{SYSTEMS.find(s=>s.id===activeSystem)?.emoji} {SYSTEMS.find(s=>s.id===activeSystem)?.label}</div>
      </div>
      <div style={{ flex:1, overflow:'hidden' }}>
        {activeSystem==='shadow'      && <ShadowCloneScreen state={state} dispatch={dispatch} showNotif={showNotif}/>}
        {activeSystem==='nemesis'     && <NemesisScreen state={state} dispatch={dispatch} addXP={addXP} showNotif={showNotif}/>}
        {activeSystem==='consequence' && <ConsequenceScreen state={state} dispatch={dispatch} showNotif={showNotif}/>}
        {activeSystem==='blackmarket' && <BlackMarketScreen state={state} dispatch={dispatch} addXP={addXP} showNotif={showNotif}/>}
        {activeSystem==='bloodline'   && <BloodlineScreen state={state} dispatch={dispatch} showNotif={showNotif}/>}
        {activeSystem==='debt'        && <DebtLedgerScreen state={state} dispatch={dispatch} addXP={addXP} showNotif={showNotif}/>}
        {activeSystem==='entropy'     && <EntropyScreen state={state} dispatch={dispatch} showNotif={showNotif}/>}
        {activeSystem==='forbidden'   && <ForbiddenZoneScreen state={state} dispatch={dispatch} addXP={addXP} showNotif={showNotif}/>}
      </div>
    </div>
  );
  return (
    <div style={{ height:'100%', display:'flex', flexDirection:'column' }}>
      <div style={{ padding:'12px 16px', flexShrink:0 }}>
        <div className="cinzel" style={{ fontSize:18, color:'#9B59B6', letterSpacing:3, marginBottom:4 }}>⚙️ SYSTEMS</div>
        <div style={{ fontSize:11, color:'var(--text-dim)' }}>Advanced mechanics that gamify every corner of your life.</div>
      </div>
      <div className="scrollable" style={{ flex:1, padding:'0 16px 24px' }}>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
          {SYSTEMS.map(s=>(
            <button key={s.id} onClick={()=>setActiveSystem(s.id)} style={{ padding:'16px 12px', borderRadius:12, cursor:'pointer', position:'relative', background:`${s.color}0a`, border:`1px solid ${s.color}33`, textAlign:'left', transition:'all 0.15s' }}>
              {s.badge && <div style={{ position:'absolute', top:8, right:8, minWidth:18, height:18, borderRadius:9, background:s.color, color:'#000', fontSize:10, fontFamily:'Cinzel,serif', display:'flex', alignItems:'center', justifyContent:'center', padding:'0 4px', fontWeight:900 }}>{s.badge}</div>}
              <div style={{ fontSize:28, marginBottom:6 }}>{s.emoji}</div>
              <div className="cinzel" style={{ fontSize:11, color:s.color, lineHeight:1.4 }}>{s.label}</div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

