  quads: ['Squat', 'Leg Press', 'Leg Extension', 'Hack Squat', 'Bulgarian Split Squat', 'Walking Lunges'],
  hamstrings: ['Romanian Deadlift', 'Leg Curl', 'Stiff-Leg Deadlift', 'Nordic Curl', 'Glute-Ham Raise'],
