  calves: ['Standing Calf Raise', 'Seated Calf Raise', 'Donkey Calf Raise', 'Jump Rope', 'Single-Leg Calf Raise'],
  hipFlexors: ['Hip Flexor Stretch', 'Mountain Climbers', 'Hanging Knee Raises', 'Cable Hip Flexion', 'Psoas March'],
